11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	};
21	
22	export function quote(input: QuoteInput): number {
23	  if (input.items.length === 0) return PROCESSING_FEE;
24	  const item = input.items[0];
25	  const base = BASE_PREMIUM[item.type];
26	  return Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
27	}
